GamePlayer = class("GamePlayer", BasePlayer)

local clickSceneCdTime = 100 --点击场景cd

function GamePlayer:init()
    self:initStaticAttr(0)
    self:initAttr()
    self:teleportPos(self:randomInitPos())
end

function GamePlayer:initAttr()
    self.property = PlayerProperty.new(self.userId)
    self.curArea = Define.Area.CommonArea
    self.advancingId = 0
    self.radius = 0
    self.timerKeys = {}
    self.isLife = true --是否活着
    self.newGuideProgress = 1  --新引导的进度 

    --商店相关
    self.shopFitnessEquip = {} --商店器材
    self.shopGene = {} --商店基因
    self.shopAdvanced = {} --商店进阶
    self.shopSkill = {} --商店技能
    self.equipmentSkill = {}  --装备的技能

    self.tokenShopFitnessEquip = {} --代币商店器材
    self.tokenShopGene = {} --代币商店基因
    self.tokenShopSkill = {} --代币商店技能

    --组队相关
    self.teamId = ""
    self.joinTime = 0
    self.clickSceneCd = 0

    --引导相关
    self.running_guides = {}
    self.finish_ids = {}

    --广告相关
    self.advertInfo = {
        dayKey = 0,
        records = {}
    }

    --锦标赛
    self.birthPos = VectorUtil.newVector4(0, 0, 0, 0) --出生点
    self.score = 0 --积分
    self.beKillScore = 0 --被击杀积分
    self.curKill = 0 --本局击杀数

    self:changeMaxHealth(self:getMaxHealth())
end

function GamePlayer:initDataFromDB(data, subKey)
    if subKey == DbUtil.GAME_DATA then
        self.property:loadProperty(data)
        LSRankManager:addPlayerRank(self)
        LSRankManager:senderAllRankToOnePlayer(self)
        TeamManager:onPlayerLogin(self)

        local config = AdvancedConfig:getAdvancedConfig(self.property.advancedLevel)
        if config then
            self.beKillScore = config.score
        end
    end

    if subKey == DbUtil.SHOP_DATA then
        if not data.__first then
            self.shopFitnessEquip = data.shopFitnessEquip or {}
            self.shopGene = data.shopGene or {}
            self.shopAdvanced = data.shopAdvanced or {}
            self.shopSkill = data.shopSkill or {}
            self.equipmentSkill = data.equipmentSkill or {}
            self.tokenShopFitnessEquip = data.tokenShopFitnessEquip or {}
            self.tokenShopGene = data.tokenShopGene or {}
            self.tokenShopSkill = data.tokenShopSkill or {}
        end
        ShopManager:initItem(self)
        ShopManager:senderAllItemInfo(self)
    end

    if subKey == DbUtil.PAY_DATA then
        self.property:loadPayData(data)
    end

    if subKey == DbUtil.GUIDE_DATA then
        if not data.__first then
            GameGuide:recoverGuide(self, data)
            self.newGuideProgress = data.newGuideProgress or 1
        end
        GameGuide:sendDataToClient(self)
        GamePacketSender:sendNewGuideProgressInfo(self.rakssid, self.newGuideProgress)
    end

    if subKey == DbUtil.ADVERT_DATA then
        if not data.__first then
            self.advertInfo = data.advertInfo
        end
        AdvertConfig:initPlayerAdvert(self)
    end

end

function GamePlayer:onReady()
    self.property.loginTime = os.time()

    HostApi.sendPlaySound(self.rakssid, ChampionShipConfig.waitGameMusic)
    GamePacketSender:sendEditionVisibleInfo(self.rakssid,true)
    self:setShowName(self:buildShowName(), 0)
    self.property:addInvincibleState(Utility.dayTime, true)
    GameStateManager:onPlayerReady(self)
end

function GamePlayer:onLogout()
    self:unbindAllEntity()
    TeamManager:onPlayerExit(self)

    self:reportPlayerLogout()
end

function GamePlayer:reportPlayerLogout()
    ReportUtil.reportPlayerFitnessEquipId(self)
    ReportUtil.reportPlayerGeneId(self)
    ReportUtil.reportPlayerAdvancedLevel(self)
    ReportUtil.reportPlayerGameTime(self)
    ReportUtil.reportPlayerGold(self)
end

function GamePlayer:onTick(ticks)
    if self.clickSceneCd > 0 then
        self.clickSceneCd = self.clickSceneCd - GameMatch.tickInterval
    end

    self.property:onTick(ticks)
end

function GamePlayer:isDead()
    return self.property.curHealth <= 0
end

--force:true-无视被抓取被投掷强制造成伤害
function GamePlayer:bePlayerAttacked(attacker, hurtType, force, skillId)
    hurtType = hurtType or Define.HurtType.Attack

    if CheckAreaRule:CheckAreaRule(self.curArea, Define.AreaRule.NotAllowHurt) then
        return
    end

    if self:isEntityAlive() == false then
        return
    end

    if attacker ~= nil then
        local damage = 0
        if hurtType == Define.HurtType.Attack then
            damage = attacker.property:getAttack(skillId)
        else
            damage = attacker.property:getSkillAttack(skillId)
        end
        self:onHurt(attacker, damage, force)
    end
end

function GamePlayer:onHurt(attacker, damage, force)
    force = force or false

    if self.property.curHealth <= 0 then
        return
    end

    if self:isEntityAlive() == false then
        return
    end

    if self.property.invincible then
        return
    end

    if self:isBeGrab() and force == false then
        return
    end

    if self:isFlyingByPulled() and force == false then
        return
    end

    self.property:changeHealth(self.property.curHealth, self.property.curHealth - damage, true)

    --伤害飘字
    local attackerId = -1
    if attacker then
        attackerId = attacker:getEntityId()
    end
    local data = tostring(damage) .. "," .. tostring(attackerId)
    PacketSender:syncEntityPlayerInfo(self.userId, "FloatNumberDamage", data)

    if self:isDead() then
        self:onDie(attacker)
    end
end

function GamePlayer:setScale(coe)
    if self.entityPlayerMP then
        self.entityPlayerMP:setScale(coe)
        self.property:setSpeedAdd(self.property:getMoveSpeed())
        self.property.lastScale = coe
        PacketSender:syncEntityPlayerInfo(self.userId, "scale#muscleMass",
                tostring(coe) .. "#" .. tostring(self.property.muscleMass))
        --LogUtil.log(string.format("GamePlayer:setScale %s %s", tostring(self.rakssid), tostring(coe)))
    end

    self.radius = self:getWidth() * self.property:getScale() * 2 ^ 0.5
    --print(string.format("self.radius %s %f", tostring(self.rakssid), self.radius))

    self.property.lastUpdateScaleTime = os.time()
end

function GamePlayer:onDie(attacker)
    LogUtil.log("GamePlayer:onDie " .. tostring(self.rakssid))

    if attacker then
        --夺取肌肉值
        local value = math.ceil(self.property.muscleMass * GameConfig.muscleCaptureCoe)
        self.property:changeMuscleMass(-value)
        attacker.property:changeMuscleMass(value)
        attacker.curKill = attacker.curKill + 1
        attacker.score = attacker.score + self.beKillScore
        LSRankManager:updatePlayerRank(attacker)

        --在摔跤大赛增加击杀数
        if attacker.property.isWrestling then
            attacker.property.wrestlingKill = attacker.property.wrestlingKill + 1
        end

        --播放进阶击杀特效
        local effectId = AdvancedConfig:getKillEffect(attacker.property.advancedLevel)
        local config = EffectConfig:getEffectConfig(effectId)
        if config then
            EngineWorld:addSimpleEffect(config.name, self:getPosition(),
                    config.effectYaw, config.liveTime, 0, config.scale)
        end
        self:sendPlayerKillPlayerMsg(attacker)
    end

    LSRankManager:updatePlayerRank(self)
    self.isLife = false
    TeamManager:onPlayerExit(self)
    self:sendPlayerSettlement()
end

function GamePlayer:sendPlayerKillPlayerMsg(attacker)

    if attacker then

        local attackerColor = FameConfig:getColorByKill(attacker.property.kill)
        local attackerFame = FameConfig:getNameByKill(attacker.property.kill)
        local playerColor = FameConfig:getColorByKill(self.property.kill)
        local playerFame = FameConfig:getNameByKill(self.property.kill)
        MsgSender.sendKillMsg(attackerColor .. attacker.name, playerColor .. self.name, 0, 0, 0, "", 0, 0, attackerFame, playerFame)
    end

end

