function GamePlayer:onRespawn()
    self:unbindAllEntity()
    self.property:onRespawn()
    self:teleportPosWithYaw1(self.birthPos)
    self:setShowName(self:buildShowName(), 0)
    self.isLife = true
end

function GamePlayer:onAfterRespawn()
