end

function GamePlayer:canAttack()
    if self.entityPlayerMP:isEntityAlive() == false then
        return false
    end
    if CheckAreaRule:CheckAreaRule(self.curArea, Define.AreaRule.NotAllowAttack) then
        return false
    end
    if self:isBeGrab() then
        return false
    end
    if self:isFlyingByPulled() then
        return false
    end
    return true
end

function GamePlayer:doQuanJi()
    if self.entityPlayerMP:isEntityAlive() == false or self.clickSceneCd > 0 then
        return
    end

    if self:isAdvancing() then

    else
        if not self:canAttack() then
            return
        end
        local players = PlayerManager:getPlayers()
        for _, player in pairs(players) do
            if player and player.rakssid ~= self.rakssid
                    and Utility.checkQuanJiRange(self, player) then
                player:bePlayerAttacked(self)
            end
        end
    end
    HostApi.sendPlaySound(0, 413)
    self:onClickSceneCd()
end

function GamePlayer:doJiaoCai()
    if self.entityPlayerMP:isEntityAlive() == false or self.clickSceneCd > 0 then
        return
    end

    if self:isAdvancing() then

    else
        if not self:canAttack() then
            return
        end
        local players = PlayerManager:getPlayers()
        for _, player in pairs(players) do
            if player and player.rakssid ~= self.rakssid
                    and MathUtil:distanceSquare2d(player:getPosition(), self:getPosition())
                    < math.pow(GameConfig.enemyRadius + self.radius * ClientConfig.adjustCoe, 2) then
                player:bePlayerAttacked(self)
            end
        end
    end
    HostApi.sendPlaySound(0, 412)
    self:onClickSceneCd()
end

function GamePlayer:sellMuscleMass()
    --将玩家的肌肉量兑换为金币
    local privilegeCoe = self.property.payItemList[tostring(Define.PayItemType.DoubleGold)] or 0
    local goldNum = (self.property.muscleMass * GameConfig.convertScale) * (1 + privilegeCoe)
    self.property:changeGold(goldNum)

    self.property:changeMuscleMass(-self.property.muscleMass)
end

function GamePlayer:randomInitPos()
    local posNum = TableUtil.getTableSize(GameConfig.initPos)
    local seq = math.random(posNum)
    return GameConfig.initPos[seq]
end

--做锻炼
function GamePlayer:doWorkout()
    if self.entityPlayerMP:isEntityAlive() == false or self:isGrab() or self:isBeGrab() or self.clickSceneCd > 0 then
        return
    end

    if CheckAreaRule:CheckAreaRule(self.curArea, Define.AreaRule.NotAllowWorkout) then
        return
    end

    if self:isFlyingByPulled() then
        return
    end

    TeamManager:countPlayerIncome(self)

    local muscle = self.property:getMuscleMassInc()
    self.property:changeMuscleMass(muscle, false)
    HostApi.sendPlaySound(self.rakssid, 411)
    self:onClickSceneCd()
end

