function GamePlayer:playSkill(skillId)
    if not self:canAttack() then
        return
    end

    local config = SkillConfig:getSkillById(skillId)

    if config == nil then
        config = TokenSkillConfig:getSkillById(skillId)
    end

    if config == nil then
        return
    end

    --判断抓取状态
    if self:isGrab() == false and config.skillType ~= Define.SkillType.Common then
        return
    end

    SkillManager:playSkill(self.userId, skillId)

    ReportUtil.reportPlaySkill(self, skillId)

    LogUtil.log(string.format("GamePlayer:playSkill %s %d", tostring(self.rakssid), skillId))
end

function GamePlayer:isAdvancing()
    return self.advancingId ~= 0
end

function GamePlayer:doPulledCollision()
    local skill = SkillManager:getSkill(self.throwSkillUid)
    if skill == nil then
        return false
    end

    local attacker = PlayerManager:getPlayerByRakssid(skill.rakssid)
    if attacker == nil then
        return false
    end

    --碰撞检测
    local entity = Utility.getPulledCollisionEntity(self, attacker)
    if entity == nil then
        return true
    end

    --伤害计算(碰撞)
    skill:doDamage(entity)

    return false
end

function GamePlayer:doReward(type, num)
    if type == Define.RewardType.Muscle then
        self.property:changeMuscleMass(num)
    else
        self.property:changeGold(num)
    end

    --通知客户端获得奖励
    local params = {}
    params.type = type
    params.num = num
    local data = DataBuilder.new():fromTable(params):getData()
    PacketSender:sendLuaCommonData(self.rakssid, "NoticeReward", data)
end

function GamePlayer:onClickSceneCd()
    self.clickSceneCd = clickSceneCdTime
end

function GamePlayer:equipSkin(id)
    self.property.skinList[tostring(SkinConfig:getDefaultSkin(self))] = 1

    local config = SkinConfig:getSkinConfig(id)
    if config == nil then
        config = TokenSkinConfig:getSkinConfig(id)
    end

    if config and self.property.skinList[tostring(id)] then
        self:changeActor(config.actor)
        self.property.skinId = id
        GamePacketSender:SendEquipSkin(self.rakssid, id, true)
    else
        EngineWorld:restorePlayerActor(self)
        GamePacketSender:SendEquipSkin(self.rakssid, self.property.skinId, false)
        self.property.skinId = id
    end

    --恢复手持物和进阶特效
    if self.property.isHoldItemActor then
        self.property:changeHoldItemActor(self.property.fitnessEquipId)
    end
    self.property:changeAdvancedLevel(self.property.advancedLevel)
end

