function GamePlayer:onReviewPlayer(targetRakssid)
    local player = PlayerManager:getPlayerByRakssid(targetRakssid)
    if not player then
        return
    end

    --print(string.format("GamePlayer:onReviewPlayer %s %s", self.name, player.name))

    PacketSender:syncEntityPlayerInfo(self.userId, "AdvancedLevel", tostring(self.property.advancedLevel), targetRakssid)
    PacketSender:syncEntityPlayerInfo(self.userId, "Invincible", tostring(self.property.invincible), targetRakssid)
    PacketSender:syncEntityPlayerInfo(self.userId, "ConcealPower", self.property.isConcealPower, targetRakssid)

    --GamePacketSender:SendAutoAreaInfo(self.userId, self.property.inAutoArea)
end

function GamePlayer:teleportPos(pos, isPlayEffect)
    if not pos then
        return
    end

    if self:isBeGrab() then
        return
    end

    if self:isGrab() then
        self:unbindAllEntity()
    end

    local lastPos = self:getPosition()

    --print(string.format("HostApi.resetPos Before %f %f %f",
    --        self:getPosition().x, self:getPosition().y, self:getPosition().z))
    HostApi.resetPos(self.rakssid, pos.x, pos.y + 0.5, pos.z)
    --print(string.format("HostApi.resetPos After %f %f %f",
    --        self:getPosition().x, self:getPosition().y, self:getPosition().z))

    isPlayEffect = isPlayEffect or false
    if isPlayEffect then
        Utility.playEffect(GameConfig.teleportEffect, lastPos)
    end
end

function GamePlayer:changeNewGuiProgress(index)
    if index > 0 and index < 99999 then
        self.newGuideProgress = index
    end
end

return GamePlayer